package org.blogs.Blogs.repository;import org.blogs.Blogs.entity.BlogLike;import org.blogs.Blogs.entity.BlogPost;import org.blogs.Blogs.entity.UserEntity;import org.springframework.data.jpa.repository.JpaRepository;import java.util.Optional;public interface BlogLikeRepository extends JpaRepository<BlogLike, Long> {    Optional<BlogLike> findByBlogAndUser(BlogPost blog, UserEntity user);    long countByBlog(BlogPost blog);    void deleteByBlogAndUser(BlogPost blog, UserEntity user);}